import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  listProjectsForStudent,
  createProject,
  listMeetingsForStudent,
  listReportsForStudent,
  submitReport,
  createMentorRequest,
  listAvailabilityForMentor,
} from "../api/resources";
import { getUserId } from "../api/users";
import logout from "../utils/logout";
import "./studentdashboard.css";

export default function StudentDashboard() {
  const navigate = useNavigate();
  const studentId = getUserId();

  const [activeTab, setActiveTab] = useState("project");
  const [project, setProject] = useState(null);
  const [reports, setReports] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [mentorSlots, setMentorSlots] = useState([]);

  const [selectedMentorId, setSelectedMentorId] = useState("");
  const [newProject, setNewProject] = useState({
    title: "",
    description: "",
  });

  const [uploadFile, setUploadFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState("");

  useEffect(() => {
    if (!studentId) {
      navigate("/login");
      return;
    }

    const load = async () => {
      try {
        const [projRes, meetRes, repRes] = await Promise.all([
          listProjectsForStudent(studentId),
          listMeetingsForStudent(studentId),
          listReportsForStudent(studentId),
        ]);
        setProject(projRes.data?.[0] || null);
        setMeetings(meetRes.data || []);
        setReports(repRes.data || []);
      } catch (err) {
        console.error(err);
      }
    };
    load();
  }, [studentId, navigate]);

  const handleCreateProject = async (e) => {
    e.preventDefault();
    try {
      await createProject({
        ...newProject,
        student_id: studentId,
      });
      alert("Project created successfully!");
      const res = await listProjectsForStudent(studentId);
      setProject(res.data?.[0] || null);
      setNewProject({ title: "", description: "" });
    } catch (err) {
      alert("Error creating project");
    }
  };

  const handleRequestMentor = async () => {
    if (!selectedMentorId) return alert("Enter a mentor ID first");
    try {
      await createMentorRequest({
        student_id: studentId,
        mentor_id: selectedMentorId,
        project_title: project?.title || "",
      });
      alert("Mentor request sent!");
    } catch (err) {
      alert("Failed to send request");
    }
  };

  const handleLoadSlots = async () => {
    try {
      const res = await listAvailabilityForMentor(selectedMentorId);
      setMentorSlots(res.data || []);
    } catch {
      alert("Error loading slots");
    }
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!uploadFile) return alert("Please choose a file");
    try {
      setUploadStatus("Uploading...");
      const formData = new FormData();
      formData.append("file", uploadFile);
      formData.append("student_id", studentId);
      await submitReport(formData);
      const repRes = await listReportsForStudent(studentId);
      setReports(repRes.data || []);
      setUploadStatus("Uploaded!");
      setUploadFile(null);
    } catch {
      setUploadStatus("Upload failed");
    }
  };

  return (
    <div className="student-dashboard">
      <div className="header">
        <h2>Student Dashboard</h2>
        <button onClick={() => logout(navigate)}>Logout</button>
      </div>

      <div className="tabs">
        {["project", "mentor", "meetings", "reports"].map((tab) => (
          <button
            key={tab}
            className={activeTab === tab ? "active" : ""}
            onClick={() => setActiveTab(tab)}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="content">
        {activeTab === "project" && (
          <div>
            <h3>Project</h3>
            {project ? (
              <div className="card">
                <h4>{project.title}</h4>
                <p>{project.description}</p>
              </div>
            ) : (
              <form onSubmit={handleCreateProject}>
                <input
                  type="text"
                  placeholder="Title"
                  value={newProject.title}
                  onChange={(e) =>
                    setNewProject({ ...newProject, title: e.target.value })
                  }
                  required
                />
                <textarea
                  placeholder="Description"
                  value={newProject.description}
                  onChange={(e) =>
                    setNewProject({ ...newProject, description: e.target.value })
                  }
                ></textarea>
                <button type="submit">Create Project</button>
              </form>
            )}
          </div>
        )}

        {activeTab === "mentor" && (
          <div>
            <h3>Request Mentor</h3>
            <input
              placeholder="Enter Mentor ID"
              value={selectedMentorId}
              onChange={(e) => setSelectedMentorId(e.target.value)}
            />
            <button onClick={handleRequestMentor}>Send Request</button>
            <button onClick={handleLoadSlots}>View Mentor Slots</button>
            <div className="slots">
              {mentorSlots.map((slot) => (
                <div key={slot.id} className="slot">
                  <p>
                    <b>{slot.day}</b> — {slot.start_time} to {slot.end_time}
                  </p>
                  <p>{slot.location}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "meetings" && (
          <div>
            <h3>Meetings</h3>
            {meetings.length === 0 ? (
              <p>No meetings yet.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Date</th>
                    <th>Time</th>
                    <th>Topic</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {meetings.map((m) => (
                    <tr key={m.id}>
                      <td>{m.date}</td>
                      <td>{m.time}</td>
                      <td>{m.topic}</td>
                      <td>{m.status}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}

        {activeTab === "reports" && (
          <div>
            <h3>Upload Report</h3>
            <form onSubmit={handleUpload}>
              <input
                type="file"
                onChange={(e) => setUploadFile(e.target.files[0])}
              />
              <button type="submit">Upload</button>
            </form>
            <p>{uploadStatus}</p>
            <h4>Your Reports</h4>
            {reports.length === 0 ? (
              <p>No reports uploaded yet.</p>
            ) : (
              <ul>
                {reports.map((r) => (
                  <li key={r.id}>
                    {r.title || r.filename} — {r.status}
                  </li>
                ))}
              </ul>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
